/**
 * Postbuild sitemap script
 * 1. Reads sitemap-0.xml (generated by next-sitemap from actual built pages)
 * 2. STRIPS all <xhtml:link> hreflang entries (next-sitemap may generate broken
 *    double-locale URLs on Vercel builds due to hrefIsAbsolute handling issues)
 * 3. REGENERATES correct absolute hreflang entries from tool JSON data files
 * 4. Splits URLs into per-locale/per-type sitemap files
 * 5. Deletes sitemap-0.xml and any stale per-locale sitemaps
 * 6. Writes sitemap.xml index pointing to all generated sitemaps
 * Run after next-sitemap: npm run postbuild
 */

const fs = require('node:fs');
const path = require('node:path');

const PUBLIC_DIR = path.join(process.cwd(), 'public');
const SITE_URL = 'https://www.arteonagency.pl';
const LOCALES = ['pl', 'en', 'de', 'es', 'fr', 'pt', 'it', 'ro', 'nl', 'hu', 'cs', 'sv', 'da', 'no', 'fi', 'el'];

const LOCALE_TOOLS_BASE = {
  pl: '/narzedzia',
  en: '/en/tools',
  de: '/de/werkzeuge',
  es: '/es/herramientas',
  fr: '/fr/outils',
  pt: '/pt/ferramentas',
  it: '/it/strumenti',
  ro: '/ro/instrumente',
  nl: '/nl/tools',
  hu: '/hu/eszkozok',
  cs: '/cs/nastroje',
  sv: '/sv/verktyg',
  da: '/da/vaerktojer',
  no: '/no/verktoy',
  fi: '/fi/tyokalut',
  el: '/el/ergaleia',
};

const LOCALE_TO_HREFLANG = {
  pl: 'pl',
  en: 'en',
  de: 'de',
  es: 'es',
  fr: 'fr',
  pt: 'pt',
  it: 'it',
  ro: 'ro',
  nl: 'nl',
  hu: 'hu',
  cs: 'cs',
  sv: 'sv',
  da: 'da',
  no: 'no',
  fi: 'fi',
  el: 'el',
};

// Locale root pages (/en, /de, …) are permanentRedirect() stubs — not real pages.
// They are excluded from this hreflang group to avoid misleading Google.
// PL homepage (/) has no multilingual equivalent and carries no hreflang.
const MULTILINGUAL_PAGES = [
  {
    pl: '/o-nas',
    en: '/en/about',
    de: '/de/ueber-uns',
    es: '/es/sobre-nosotros',
    fr: '/fr/a-propos',
    pt: '/pt/sobre-nos',
    it: '/it/chi-siamo',
    ro: '/ro/despre-noi',
    nl: '/nl/over-ons',
    hu: '/hu/rolunk',
    cs: '/cs/o-nas',
    sv: '/sv/om-oss',
    da: '/da/om-os',
    no: '/no/om-oss',
    fi: '/fi/tietoa-meista',
    el: '/el/sxetika-me-emas',
  },
  {
    pl: '/kontakt',
    en: '/en/contact',
    de: '/de/kontakt',
    es: '/es/contacto',
    fr: '/fr/contact',
    pt: '/pt/contacto',
    it: '/it/contatto',
    ro: '/ro/contact',
    nl: '/nl/contact',
    hu: '/hu/kapcsolat',
    cs: '/cs/kontakt',
    sv: '/sv/kontakt',
    da: '/da/kontakt',
    no: '/no/kontakt',
    fi: '/fi/yhteystiedot',
    el: '/el/epikoinonia',
  },
  {
    pl: '/polityka-prywatnosci',
    en: '/en/privacy-policy',
    de: '/de/datenschutzrichtlinie',
    es: '/es/politica-de-privacidad',
    fr: '/fr/politique-de-confidentialite',
    pt: '/pt/politica-de-privacidade',
    it: '/it/informativa-sulla-privacy',
    ro: '/ro/politica-de-confidentialitate',
    nl: '/nl/privacybeleid',
    hu: '/hu/adatvedelmi-iranyelvek',
    cs: '/cs/zasady-ochrany-soukromi',
    sv: '/sv/integritetspolicy',
    da: '/da/privatlivspolitik',
    no: '/no/personvernpolicy',
    fi: '/fi/tietosuojakaytanto',
    el: '/el/politiki-aporritou',
  },
  {
    pl: '/regulamin',
    en: '/en/terms-of-service',
    de: '/de/nutzungsbedingungen',
    es: '/es/terminos-de-servicio',
    fr: '/fr/conditions-utilisation',
    pt: '/pt/termos-de-servico',
    it: '/it/termini-di-servizio',
    ro: '/ro/termeni-si-conditii',
    nl: '/nl/gebruiksvoorwaarden',
    hu: '/hu/felhasznalasi-feltetelek',
    cs: '/cs/podminky-pouzivani',
    sv: '/sv/anvandarvillkor',
    da: '/da/brugsvilkar',
    no: '/no/bruksvilkar',
    fi: '/fi/kayttoehdot',
    el: '/el/oroi-chrisis',
  },
];

const XML_HEADER =
  '<?xml version="1.0" encoding="UTF-8"?>\n<urlset xmlns="http://www.sitemaps.org/schemas/sitemap/0.9" xmlns:xhtml="http://www.w3.org/1999/xhtml" xmlns:image="http://www.google.com/schemas/sitemap-image/1.1">';
const XML_FOOTER = '</urlset>';

// ---------------------------------------------------------------------------
// Build tool locale paths from JSON data files (single source of truth)
// ---------------------------------------------------------------------------
function buildToolLocalePathsMap() {
  const byKey = new Map();
  for (const locale of LOCALES) {
    const dir = path.join(process.cwd(), 'data', locale, 'tools');
    if (!fs.existsSync(dir)) continue;
    const files = fs.readdirSync(dir).filter((f) => f.endsWith('.json'));
    for (const file of files) {
      try {
        const data = JSON.parse(fs.readFileSync(path.join(dir, file), 'utf8'));
        if (!data.toolKey || !data.metadata?.path) continue;
        if (!byKey.has(data.toolKey)) byKey.set(data.toolKey, {});
        byKey.get(data.toolKey)[locale] = data.metadata.path;
      } catch {
        /* skip malformed files */
      }
    }
  }
  return byKey;
}

// Reverse map: path → toolKey
function buildPathToToolKey(toolLocalePathsMap) {
  const map = new Map();
  for (const [key, localePaths] of toolLocalePathsMap.entries()) {
    for (const lpath of Object.values(localePaths)) {
      map.set(lpath, key);
    }
  }
  return map;
}

// ---------------------------------------------------------------------------
// Generate correct hreflang <xhtml:link> entries for a given URL path
// ---------------------------------------------------------------------------
function generateHreflangLinks(urlPath, toolLocalePathsMap, pathToToolKey) {
  // Tool index pages
  if (Object.values(LOCALE_TOOLS_BASE).includes(urlPath)) {
    const links = LOCALES.map((lang) => `<xhtml:link rel="alternate" hreflang="${LOCALE_TO_HREFLANG[lang]}" href="${SITE_URL}${LOCALE_TOOLS_BASE[lang]}"/>`);
    links.push(`<xhtml:link rel="alternate" hreflang="x-default" href="${SITE_URL}${LOCALE_TOOLS_BASE.en}"/>`);
    return links.join('');
  }

  // Individual tool pages
  const toolKey = pathToToolKey.get(urlPath);
  if (toolKey) {
    const localePaths = toolLocalePathsMap.get(toolKey);
    const links = Object.entries(localePaths).map(([lang, href]) => `<xhtml:link rel="alternate" hreflang="${LOCALE_TO_HREFLANG[lang] || lang}" href="${SITE_URL}${href}"/>`);
    const enPath = localePaths['en'];
    if (enPath) links.push(`<xhtml:link rel="alternate" hreflang="x-default" href="${SITE_URL}${enPath}"/>`);
    return links.join('');
  }

  // Non-tool multilingual pages (homepage, about, contact, privacy, terms)
  for (const page of MULTILINGUAL_PAGES) {
    if (Object.values(page).includes(urlPath)) {
      const links = Object.entries(page).map(([lang, href]) => `<xhtml:link rel="alternate" hreflang="${LOCALE_TO_HREFLANG[lang] || lang}" href="${SITE_URL}${href}"/>`);
      links.push(`<xhtml:link rel="alternate" hreflang="x-default" href="${SITE_URL}${page.en}"/>`);
      return links.join('');
    }
  }

  return '';
}

/** Determine which sitemap file a URL path belongs to */
function categorize(urlPath) {
  for (const [locale, base] of Object.entries(LOCALE_TOOLS_BASE)) {
    if (urlPath === base || urlPath.startsWith(base + '/')) {
      return `sitemap-tools-${locale}.xml`;
    }
  }
  if (urlPath.startsWith('/uslugi')) return 'sitemap-services.xml';
  if (urlPath.startsWith('/edukacja')) return 'sitemap-education.xml';
  if (urlPath.startsWith('/realizacje')) return 'sitemap-projects.xml';
  return 'sitemap-pages.xml';
}

function main() {
  const sitemap0Path = path.join(PUBLIC_DIR, 'sitemap-0.xml');
  if (!fs.existsSync(sitemap0Path)) {
    console.warn('⚠️  sitemap-0.xml not found — skipping split');
    process.exit(0);
  }

  // Build hreflang data from JSON files
  const toolLocalePathsMap = buildToolLocalePathsMap();
  const pathToToolKey = buildPathToToolKey(toolLocalePathsMap);
  console.log(`  ℹ Loaded ${toolLocalePathsMap.size} tools × ${LOCALES.length} locales for hreflang`);

  // 1. Parse sitemap-0.xml into individual <url> blocks
  const xml = fs.readFileSync(sitemap0Path, 'utf8');
  const urlBlocks = xml.match(/<url>[\s\S]*?<\/url>/g) || [];

  // 2. Strip broken hreflang from next-sitemap, regenerate correct ones, split by locale
  let hreflangFixed = 0;
  const buckets = new Map();
  for (const block of urlBlocks) {
    const locMatch = block.match(/<loc>([^<]+)<\/loc>/);
    if (!locMatch) continue;
    const fullUrl = locMatch[1];
    const urlPath = fullUrl.replace(SITE_URL, '');

    // Strip ALL existing <xhtml:link> entries (may be broken from next-sitemap)
    let cleanBlock = block.replace(/<xhtml:link[^>]*\/>/g, '');

    // Generate correct hreflang entries
    const hreflangXml = generateHreflangLinks(urlPath, toolLocalePathsMap, pathToToolKey);
    if (hreflangXml) {
      // Insert hreflang just before </url>
      cleanBlock = cleanBlock.replace('</url>', `${hreflangXml}</url>`);
      hreflangFixed++;
    }

    const file = categorize(urlPath);
    if (!buckets.has(file)) buckets.set(file, []);
    buckets.get(file).push(cleanBlock);
  }

  console.log(`  ℹ Regenerated hreflang for ${hreflangFixed}/${urlBlocks.length} URLs`);

  // 3. Delete ALL old sitemap-*.xml files (except sitemap.xml itself)
  const oldFiles = fs.readdirSync(PUBLIC_DIR).filter((f) => f.startsWith('sitemap-') && f.endsWith('.xml'));
  for (const f of oldFiles) {
    fs.unlinkSync(path.join(PUBLIC_DIR, f));
  }

  // 4. Write new per-locale/per-type sitemap files
  for (const [file, blocks] of buckets.entries()) {
    const content = [XML_HEADER, ...blocks, XML_FOOTER].join('\n');
    fs.writeFileSync(path.join(PUBLIC_DIR, file), content, 'utf8');
    console.log(`  ✓ ${file} (${blocks.length} URLs)`);
  }

  // 5. Write sitemap index (with <lastmod> per sub-sitemap for efficient Google re-crawling)
  const sitemapFiles = fs
    .readdirSync(PUBLIC_DIR)
    .filter((f) => f.startsWith('sitemap-') && f.endsWith('.xml'))
    .sort();

  const entries = sitemapFiles
    .map((f) => {
      // Extract the newest <lastmod> from the sub-sitemap to include in the index
      const content = fs.readFileSync(path.join(PUBLIC_DIR, f), 'utf8');
      const lastmods = [...content.matchAll(/<lastmod>([^<]+)<\/lastmod>/g)].map((m) => m[1]);
      const newest = lastmods.sort().pop();
      const lastmodTag = newest ? `<lastmod>${newest}</lastmod>` : '';
      return `<sitemap><loc>${SITE_URL}/${f}</loc>${lastmodTag}</sitemap>`;
    })
    .join('\n');

  const sitemapIndex = ['<?xml version="1.0" encoding="UTF-8"?>', '<sitemapindex xmlns="http://www.sitemaps.org/schemas/sitemap/0.9">', entries, '</sitemapindex>'].join('\n');

  fs.writeFileSync(path.join(PUBLIC_DIR, 'sitemap.xml'), sitemapIndex, 'utf8');
  console.log(`✓ sitemap.xml index → ${sitemapFiles.length} sitemaps, ${urlBlocks.length} total URLs`);
}

main();
